#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Structure to represent a data point
typedef struct {
 double x;
 double y;
} DataPoint;

// Function to calculate Euclidean distance
double distance(DataPoint p1, DataPoint p2) {
 return sqrt(pow(p1.x - p2.x, 2) + pow(p1.y - p2.y, 2));
}

// Function to perform K-Means clustering
void kmeans(DataPoint* data, int n, int k) {
 // Initialize centroids randomly
 DataPoint centroids[k];
 for (int i = 0; i < k; i++) {
 centroids[i].x = data[i].x;
 centroids[i].y = data[i].y;
 }

 // Iterate until convergence
 while (1) {
 // Assign each data point to the closest centroid
 int labels[n];
 for (int i = 0; i < n; i++) {
 double min_distance = INFINITY;
 int closest_centroid = -1;
 for (int j = 0; j < k; j++) {
 double distance_ij = distance(data[i], centroids[j]);
 if (distance_ij < min_distance) {
 min_distance = distance_ij;
 closest_centroid = j;
 }
 }
 labels[i] = closest_centroid;
 }

 // Update centroids
 for (int i = 0; i < k; i++) {
 double sum_x = 0;
 double sum_y = 0;
 int count = 0;
 for (int j = 0; j < n; j++) {
 if (labels[j] == i) {
 sum_x += data[j].x;
 sum_y += data[j].y;
 count++;
 }
 }
 if (count > 0) {
 centroids[i].x = sum_x / count;
 centroids[i].y = sum_y / count;
 }
 }

 // Check for convergence
 int converged = 1;
 for (int i = 0; i < k; i++) {
 if (centroids[i].x != data[i].x || centroids[i].y != data[i].y) {
 converged = 0;
 break;
 }
 }
 if (converged) break;
 }
}
